function solve(grid, k) {
  const m = grid.length;
  const n = grid[0].length;
  const visited = Array(m).fill().map(() => Array(n).fill(false));
  let count = 0;

  function dfs(i, j, total, mod, hash) {
    if (i < 0 || i >= m || j < 0 || j >= n || visited[i][j] || grid[i][j] === 0) {
      return;
    }

    visited[i][j] = true;
    total += grid[i][j];
    mod = total % k;
    hash[mod] = (hash[mod] || 0) + 1;

    dfs(i - 1, j, total, mod, hash);
    dfs(i + 1, j, total, mod, hash);
    dfs(i, j - 1, total, mod, hash);
    dfs(i, j + 1, total, mod, hash);
